# System16 default Linux VT keymap: German QWERTZ, no dead keys.
# Modifier maps: plain, Shift, AltGr, Control, Shift-Control, Alt, Ctrl-Alt.
keymaps 0-2,4-5,8,12

keycode   1 = Escape           Escape
	alt     keycode   1 = Meta_Escape
keycode   2 = one              exclam
keycode   3 = two              quotedbl         twosuperior
	control keycode   3 = nul
keycode   4 = three            section          threesuperior
	control keycode   4 = Escape
keycode   5 = four             dollar
	control keycode   5 = Control_backslash
keycode   6 = five             percent
	control keycode   6 = Control_bracketright
keycode   7 = six              ampersand
keycode   8 = seven            slash            braceleft
	control keycode   8 = Control_underscore
keycode   9 = eight            parenleft        bracketleft
	control keycode   9 = Delete
keycode  10 = nine             parenright       bracketright
keycode  11 = zero             equal            braceright
keycode  12 = ssharp           question         backslash
	control keycode  12 = Control_backslash
keycode  13 = apostrophe       grave            asciitilde
keycode  14 = Delete           Delete
	control keycode  14 = BackSpace
keycode  15 = Tab              Tab
	alt     keycode  15 = Meta_Tab

